           return true;
         auto *BB = Inst->getParent();
-        if (isa<PHINode>(Inst) && BB->getFirstInsertionPt() == BB->end())
+        if (isa<PHINode>(Inst) && !BB->hasInsertionPt())
           return true;
         return false;
       }))
@@ -1133,7 +1133,7 @@ Instruction *InstCombinerImpl::SliceUpIllegalIntegerPHI(PHINode &FirstPhi) {
