+      if (!Pred->hasInsertionPt())
         return nullptr;

     for (User *U : PN->users()) {
@@ -1451,8 +1451,7 @@ Instruction *InstCombinerImpl::visitPHINode(PHINode &PN) {

   // If the incoming values are pointer casts of the same original value,
